	@Test
	public void defaultStoreUsesBloomEvaluationStrategyFactory() {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));

		assertInstanceOf(LmdbEvaluationStrategyFactory.class, store.getEvaluationStrategyFactory());
	}

	@Test
	public void snapshotReadDatasetExposesBloomSnapshotToEvaluationStrategy() throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			try (SailSource branch = store.getSailStore().getExplicitSailSource().fork();
					SailDataset dataset = branch.dataset(IsolationLevels.SNAPSHOT_READ)) {
				LmdbEvaluationStrategyFactory factory = (LmdbEvaluationStrategyFactory) store
						.getEvaluationStrategyFactory();
				EvaluationStrategy strategy = factory.createEvaluationStrategy(null,
						new SailDatasetTripleSource(store.getValueFactory(), dataset),
						store.getSailStore().getEvaluationStatistics());

				LmdbEvaluationStrategy lmdbStrategy = assertInstanceOf(LmdbEvaluationStrategy.class, strategy);
				assertNotNull(bloomFilterSnapshot(lmdbStrategy));
			}
		} finally {
			repository.shutDown();
		}
	}

	@Test
	public void optimizedStarJoinContainsGateAndPreservesResults() {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			ValueFactory vf = SimpleValueFactory.getInstance();
			IRI steve = vf.createIRI(NS, "steve");
			IRI alice = vf.createIRI(NS, "alice");
			IRI bob = vf.createIRI(NS, "bob");
			IRI person = vf.createIRI(NS, "Person");
			IRI knows = vf.createIRI(NS, "knows");
			IRI name = vf.createIRI(NS, "name");
			IRI email = vf.createIRI(NS, "email");
			IRI phone = vf.createIRI(NS, "phone");

			try (RepositoryConnection connection = repository.getConnection()) {
				connection.add(steve, knows, alice);
				connection.add(steve, knows, bob);
				connection.add(alice, RDF.TYPE, person);
				connection.add(alice, name, vf.createLiteral("Alice"));
				connection.add(alice, email, vf.createLiteral("alice@example.org"));
				connection.add(alice, phone, vf.createLiteral("+47 1"));
				connection.add(bob, RDF.TYPE, person);
				connection.add(bob, name, vf.createLiteral("Bob"));

				String query = String.join("\n",
						"PREFIX : <urn:lmdb-bloom:>",
						"SELECT ?name ?email ?phone",
						"WHERE {",
						"  :steve :knows ?person.",
						"  ?person a :Person.",
						"  ?person :name ?name.",
						"  ?person :email ?email.",
						"  ?person :phone ?phone.",
						"}");

				String explanation = connection.prepareTupleQuery(QueryLanguage.SPARQL, query)
						.explain(Explanation.Level.Optimized)
						.toString();
				assertTrue(explanation.contains("LmdbBloomFilterGate"), explanation);

				try (TupleQueryResult result = connection.prepareTupleQuery(QueryLanguage.SPARQL, query).evaluate()) {
					List<String> names = result.stream()
							.map(bindings -> bindings.getValue("name").stringValue())
							.collect(Collectors.toList());
					assertEquals(List.of("Alice"), names);
				}
			}
		} finally {
			repository.shutDown();
		}
	}

