	@Test
	public void logsBloomFilterUsefulnessForQuery() {
		Logger logger = (Logger) LoggerFactory.getLogger(LmdbEvaluationStrategy.class);
		Level previousLevel = logger.getLevel();
		CapturingAppender appender = new CapturingAppender();
		appender.setContext((LoggerContext) LoggerFactory.getILoggerFactory());
		logger.addAppender(appender);
		appender.start();
		logger.setLevel(Level.INFO);

		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			ValueFactory vf = SimpleValueFactory.getInstance();
			IRI steve = vf.createIRI(NS, "logSteve");
			IRI alice = vf.createIRI(NS, "logAlice");
			IRI bob = vf.createIRI(NS, "logBob");
			IRI person = vf.createIRI(NS, "LogPerson");
			IRI knows = vf.createIRI(NS, "logKnows");
			IRI name = vf.createIRI(NS, "logName");
			IRI email = vf.createIRI(NS, "logEmail");

			try (RepositoryConnection connection = repository.getConnection()) {
				connection.add(steve, knows, alice);
				connection.add(steve, knows, bob);
				connection.add(alice, RDF.TYPE, person);
				connection.add(alice, name, vf.createLiteral("Alice"));
				connection.add(alice, email, vf.createLiteral("alice@example.org"));
				connection.add(bob, RDF.TYPE, person);
				connection.add(bob, name, vf.createLiteral("Bob"));

				String query = String.join("\n",
						"PREFIX : <urn:lmdb-bloom:>",
						"SELECT ?name ?email",
						"WHERE {",
						"  :logSteve :logKnows ?person.",
						"  ?person a :LogPerson.",
						"  ?person :logName ?name.",
						"  ?person :logEmail ?email.",
						"}");

				try (TupleQueryResult result = connection.prepareTupleQuery(QueryLanguage.SPARQL, query).evaluate()) {
					List<String> names = result.stream()
							.map(bindings -> bindings.getValue("name").stringValue())
							.collect(Collectors.toList());
					assertEquals(List.of("Alice"), names);
				}
			}
		} finally {
			repository.shutDown();
			logger.detachAppender(appender);
			appender.stop();
			logger.setLevel(previousLevel);
		}

		List<String> messages = appender.messages(Level.INFO);
		assertTrue(messages.stream()
				.anyMatch(message -> message.contains("LMDB bloom filter usage")
						&& message.contains("var=person")
						&& message.contains("checked=")
						&& message.contains("pruned=")
						&& message.contains("passed=")),
				messages.toString());
	}

	private LmdbBloomFilterSnapshot bloomFilterSnapshot(LmdbEvaluationStrategy strategy) throws Exception {
		Field field = LmdbEvaluationStrategy.class.getDeclaredField("bloomFilterSnapshot");
		field.setAccessible(true);
		return (LmdbBloomFilterSnapshot) field.get(strategy);
	}

	private static final class CapturingAppender extends ListAppender<ILoggingEvent> {
		private List<String> messages(Level level) {
			return list.stream()
					.filter(event -> event.getLevel().equals(level))
					.map(ILoggingEvent::getFormattedMessage)
					.collect(Collectors.toList());
		}
	}
